import React, { useContext, useEffect, useState } from "react";
import { UserContext } from "../context/UserContext";
import axios from "axios";

const OrdersPage = () => {
  const { user, ready } = useContext(UserContext);
  const [bookedData, setBookedData] = useState([]);
  useEffect(() => {
    const fetchData = async () => {
      try {
        if (user) {
          axios.defaults.headers.common.Authorization = `Bearer ${user?.token}`;
          const response = await axios.get("/booking/bookeditem");
          setBookedData(() => response.data);
        }
      } catch (error) {
        console.log(error);
      }
    };
    fetchData();
  }, [user]);
  return (
    <div>
      <div className="m-4 max-w-96">
      {
  bookedData.length > 0 ? (
    <>
    <div>
      <h1 >Your Past Orders</h1>
    </div>
    
      {bookedData.map((data, index) => {
        return (
          <div key={index} className="m-4">
            <h1>{data.itemid.iname}</h1>
            <div className="">
              {data.itemid.photos && (
                <div
                  className="h-32 flex max-w-96 p-2 justify-center"
                  key={data.itemid._id}
                >
                  <img
                    className="rounded-2xl w-full object-cover"
                    alt="img not found"
                    src={"http://localhost:5000/" + data.itemid?.photos[0]}
                  />
                </div>
              )}
            </div>
            <div className="flex justify-around">
              <h3>{data.itemid.imrp}</h3>
              <h3>{data.itemid.isize}</h3>
            </div>
          </div>
        );
      })}
    </>
  ) : (
    <div className="flex mt-8 justify-center ">
      <div className="w-64 h-24 bg-red-400 flex justify-center items-center font-semibold">
        No Booked Items Found
      </div>
    </div>
  )
}
      </div>
    </div>
  );
};

export default OrdersPage;
